content:
epScript 기초 [1] epScript란? eudplib Script -> epScript , 즉 eudplib 스크립트 의 약자입니다. epScript 를 사용하면 원래 eudplib에서 쓰는 파이썬 코드보다 더 읽기 쉬운 코드를 만들 수 있습니다.
트리거의 개념이 없습니다. 조건과 액션만 있습니다. Deaths 조건이나 a == b 같은 변수 비교나 똑같은 조건이고, dwread_epd 함수나 SetMemory 액션이나 똑같은 함수로 다룹니다. 그래서 이런 식으로 코드를 짤 수 있습니다.
/**
* Regenerate player, if player has sufficient life
*/
function regeneratePlayer ( player ) {
// Regenerate player
if (!Command(player, AtLeast, 1 , "Avoider" )
&& Accumulate(player, AtLeast, 1 , Ore)) {
createPlayer(player);
SetCurrentPlayer(player);
DisplayText( "\x05 Retry..." );
}
} DisplayText 같은 액션이나 createPlayer 같은 eudplib 함수 를 저런 식으로 섞어쓸 수 있고, 조건들도 if 문 안에 아무 생각 없이 넣고 ! (not), && (and), || (or)같은 논리연산도 아무 생각 없이 적용할 수 있습니다.
그냥 아무 생각 없이 코드를 짜도 epScript 가 알아서 다 해줍니다.
문법이 훨씬 단순합니다. eudplib 코드를 짜면 EUDIf()(~) 같은 괴랄한 문법을 써서 코드를 짜야 할텐데, epScript에선 그냥 if(~) 처럼 진짜 프로그래밍하듯이 코드를 짜면 됩니다. 변수 선언도 그냥 var 로 하면 되고요. EUDVariable 같은거 필요 없어요.
/**
* Sort array
* @param {[type]} arr_ [description]
* @param {[type]} n [description]
* @return {[type]} [description]
*/
function sortArray ( arr_, n ) {
const arr = EUDArray(arr_);
var t;
for ( var i = 0 ; i < n ; i++) {
for ( var j = 1 ; j < n ; j++) {
if (arr[j - 1 ] > arr[j]) {
t, arr[j], arr[j - 1 ] = arr[j], arr[j - 1 ], t;
}
}
}
}
이렇게 그냥 버블소트를 구현할 수 있습니다. 중간에 t, arr[j], arr[j - 1] ~ 부분은 swap에요 그냥
var t; 같이 모든 변수는 EUDVariable 이고, 배열이나 구조체같은걸 다루려면 const 를 써야합니다.
EUDArray 같은 eudplib에 있는 파이썬 코드를 쓰는것도 쉽습니다. const arr = EUDArray(arr_); 같은 식으로 할 수도 있고, 아래와 같은 식으로 할수도 있고요. const bgmContent = py_open( 'src/bgm22050.wav' , 'rb' ).read();
function bgmloop ( ) {
MPQAddWave( 'staredit\\wav\\bgmmain.wav' , bgmContent);
if (isTimerHit()) {
startTimer( 54857 );
SetCurrentPlayer(getuserplayerid());
PlayWAV( 'staredit\\wav\\bgmmain.wav' );
}
} py_open 으로 파이썬 open (파일을 여는 함수)을 통해 배경음악 파일을 열고 MPQAddWave 로 이 배경음악 파일을 mpq에 넣었습니다.
[2] 문법 기초 모든 epScript 파일의 확장자는 eps입니다. .eps 파일은 .py 파일과 마찬가지로 쓸 수 있습니다. import a -> a.eps 파일을 파이썬 코드에서 import 합니다. cf) euddraft 세팅 파일인 eds 랑은 다릅니다.
문법은 자바스크립트에서 많이 채용했습니다.
(1) 함수 선언 function [함수이름] ( 인자 1 , 인자 2 , ... ,인자n ) {
(내용)
return x, y, z, 123 ; // 함수 안에선 이런 식으로 여러개 값을 리턴할 수 있습니다.
} (2) if 문 if ( ~ ) {
~
} else if (~) {
~
} else {
~
} (3) for for ( var i = 0 ; i < 5 ; i++) {
~
} (4) foreach foreach(ptr, epd : EUDLoopUnit()) {
~
} 참고: 파이썬 기준으로 다음과 같습니다.
for ptr, epd in EUDLoopUnit():
~ (5) 변수 var i = 0 ; i = 123 ; // 변수에 값 대입. eudplib의 " i << 123 "에 해당합니다.
var p1, p2 = 1 , 2 ; // p1, p2 를 1, 2 로 초기화
var w0, w1, b0, b1, b2, b3 = dwbreak( 0x12345678 );
var w0, w1 = dwbreak( 0x12345678 )[[ 0 , 1 ]]; // f_dwbreak의 결과에서 0, 1번 결과만 뽑아낸다.

var x = dwbreak( 0x12345678 )[[ 0 ]]; // f_dwbreak의 결과에서 0번 결과만 뽑아낸다. ([0]을 쓰면 안됩니다)
a, b, c = b, c, a // a = b; b = c; c = a; 의 줄임말. 3개 대입이 순서대로 일어납니다.
// **** a, b, c에 각각 b, c, a의 원래 값이 대입된단 의미가 아닙니다. (6) 상수( const ) const i = 0 ; i = 1 ; // 에러 - const에 다시 값을 대입할수는 없습니다.
// EUDVariable 외에 EUDArray같은 자료형을 쓰고싶을 때에도 활용할 수 있습니다.
var arr_;
const arr = EUDArray.cast(arr_); // arr_가 주소일 때, arr는 이 주소가 가르키는 EUDArray를 나타냅니다. (7) 스타 상수 $P1 // Player1에 해당하는 플레이어 번호 (0)
$Force1 // Force1에 해당하는 플레이어 번호
$Ore $Gas // Accumulate/SetResources에서 쓰는 자원 종류 참고) $Kills - Kills라는 점수 타입에 대한 번호. Kills 조건과는 관련이 없습니다.
(8) 맵 관련 $U( "Terran Marine" ) // 테란 마린의 유닛 번호 (0)
$L( "Anywhere" ) // Anywhere 로케이션의 번호 - 63
$S( "Switch 1" ) // Switch 1의 스위치 번호
$T( "Untitled scenario" ) // 맵 스트링 번호 (9) 조건 Bring(~) // 스타 조건 Bring
a == 1 // 변수 a가 1이랑 같은가?
Bring(~) && a == 1 // 두가지 조건 동시 만족
Bring(~) || Command(~) // 둘중 하나 이상 만족
!Bring(~) // Bring이 거짓이라면 (10) import (파이썬에서 import 랑 동일) import a; // a 모듈을 불러온다.
import aa.bb; // aa.bb 모듈을 bb란 이름으로 import
import a as t; // a 모듈을 t라는 이름으로 import [3] 예시 코드 import player.playerProc as pProc;
import bulletBase as bBase;
import unitloopHelper;
/**
* Unit loop is very, very expensive. Condense all unit-related logic to here
*/
function mainUnitLoop ( ) {
// Kill clipped bullets
KillUnitAt(All, '(any unit)' , 'uclip' , Force2);
KillUnitAt(All, '(any unit)' , 'lclip' , Force2);
KillUnitAt(All, '(any unit)' , 'dclip' , Force2);
KillUnitAt(All, '(any unit)' , 'rclip' , Force2);
foreach(ptr, epd : unitloopHelper.EUDLoopUnit2()) {
const w1, b0, b1 = dwbreak(dwread_epd(epd + ( 0x4C / 4 )))[[ 1 , 2 , 3 ]];
const player, orderID = b0, b1;
if (player <= $P6) {
// Player process
const unitType = dwread_epd(epd + ( 0x64 / 4 ));
if (unitType == $U( "Avoider" )) {
pProc.processPlayerCUnit(player, ptr, epd);
continue ;
}
}
else {
// If halted -> kill it
if (orderID == 156 || orderID == 160 || orderID == 2 || orderID == 3 ) {
dwwrite_epd(epd + ( 0x4C / 4 ), w1 * 65536 + b0);
}
}
}
} 그냥 이렇게 unitloop.eps 에 써두고 다른 eps/파이썬 코드에서 import unitloop; 하면 됩니다. 그러면
.eps 파일에선 mainUnitLoop 를 부르면 되고 .py 파일에선 f_mainUnitLoop 를 부르면 됩니다. [4] euddraft 플러그인 코드도 eps 확장자로 쓸 수 있습니다.
[출처] epScript 기초 (스타 에디터 아카데미 - 맵 제작 연구·커뮤니티) |작성자 트리거왕

