- furina: https://blog.naver.com/kein0011/221236216649 // object

수학, 이진 탐색 function atan2 ( y, x ) { return angle; } y/x 의 역탄젠트를 계산합니다. (x, y) 방향의 각도를 계산합니다.
y , x : 방향을 구할 좌표. angle : (x, y) 방향의 각도. 0~360도.
function lengthdir ( length, angle ) { return x, y; } angle 방향( dir ection)으로 길이( length )만큼 움직였을 때 x , y 좌표를 계산하는 함수입니다.
length : 길이. angle : 0~360도 사이 각도. x , y : angle 방향으로 length 만큼 움직였을 때 좌표.

atan2(y, x)는 x랑 y로 각도를 구하고,

lengthdir(length, angle)은 각도랑 길이로 x, y를 구한다고 이해하시면 됩니다.

function sqrt ( n ) { return x; } n 의 제곱근을 계산합니다.
n : 제곱근을 계산할 값. x : n 의 제곱근.
function EUDBinaryMax ( cond: function, minv= 0 , maxv= 0xFFFFFFFF ) { return x; }
function EUDBinaryMin ( cond: function, minv= 0 , maxv= 0xFFFFFFFF ) { return x; } [minv 이상, maxv 이하] 의 범위에서 cond(x) 을 조건으로 만족하는 x 의 최대값/최소값을 계산합니다.
cond : 참 또는 거짓 을 리턴하고, 인자가 1개인 함수. minv : 생략 가능(기본값=0). x 의 최소 범위. maxv : 생략 가능(기본값=0xFFFFFFFF). x 의 최대 범위. x : 함수 cond 의 인자로 쓰였을 때 cond(x) 를 참 으로 만족하는 최대값/최소값. // 예시: 로케이션에 있는 유닛 수 가져오기
// (디펜스 맵에서 남은 적 유닛 수 출력하기)
function helperFunc ( x ) {
// 로케이션 "P1 Area", "P2 Area", "P3 Area", ...를 번호가 연속하도록 배치해야함.
const location = getcurpl() + ($L( "P1 Area" ) + 1 ); // 왜 1을 더하는 지는 [링크] 참고
return l2v (Bring(P8, AtLeast, x, "Men" , location)) ;
}
function afterTriggerExec ( ) {
foreach(player : EUDLoopPlayer()) {
SetCurrentPlayer(player);
const count = EUDBinaryMax(helperFunc, maxv= 1700 );
eprintf( "남은 수: {}" , count);
}
}

// 익명 함수를 사용한 버전
function afterTriggerExec ( ) {
foreach(player : EUDLoopPlayer()) {
// 로케이션 "P1 Area", "P2 Area", "P3 Area", ...를 번호가 연속하도록 배치해야함.
const location = player + ($L( "P1 Area" ) + 1 );
const count = EUDBinaryMax( function ( x ) { // 익명 함수
return l2v (Bring(P8, AtLeast, x, "Men" , location)) ;
}, maxv= 1700 );
SetCurrentPlayer(player);
eprintf( "남은 수: {}" , count);
}
} 참고) sqrt 의 구현에도 EUDBinaryMax 가 사용되었습니다.
@EUDFunc
def f_sqrt (n) :
return EUDBinaryMax( lambda x: x * x <= n, 0 , 0xFFFF )

